#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 3e5+5;
struct node{
    int x,y,z,t,res;
}p[N],a[N],tmp[N];
int m,n,ppp,c[N],ans[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(node d1,node d2){
    if(d1.x!=d2.x)return d1.x<d2.x;
    return (d1.y<d2.y)||(d1.y==d2.y&&d1.z<d2.z);
}
void upd(int x,int k){while(x<=ppp)c[x]+=k,x+=x&-x;return;}
int ask(int x){int sum=0;while(x)sum+=c[x],x-=x&-x;return sum;}
void CDQsolve(int l,int r){
    if(l==r)return;
    int mid=(l+r)>>1;
    CDQsolve(l,mid),CDQsolve(mid+1,r);
    int p1=l,p2=mid+1;
    for(int i=l;i<=r;i++)
        if(p2>r||(p1<=mid&&a[p1].y<=a[p2].y))
            upd(a[p1].z,a[p1].t),tmp[i]=a[p1],++p1;
        else tmp[i]=a[p2],tmp[i].res+=ask(a[p2].z),++p2;
    for(int i=l;i<=mid;i++)upd(a[i].z,-a[i].t);
    for(int i=l;i<=r;i++)
        a[i]=tmp[i],tmp[i]={0,0,0,0,0};
    return;
}
int main(){
    m=read(),ppp=read();
    for(int i=1;i<=m;i++)
        p[i].x=read(),p[i].y=read(),p[i].z=read();
    sort(p+1,p+m+1,cmp);
    for(int i=1;i<=m;a[n].t++,i++)
        if(p[i].x!=a[n].x||p[i].y!=a[n].y||p[i].z!=a[n].z)a[++n]=p[i];
    CDQsolve(1,n);
    for(int i=1;i<=n;i++)ans[a[i].res+a[i].t-1]+=a[i].t;
    for(int i=0;i<m;i++)cout<<ans[i]<<"\n";
    return 0;
}
